"""
Represents the checkers board with a grid of squares and pieces.
"""

class Piece:
    def __init__(self, color, is_king=False):
        self.color = color
        self.is_king = is_king

    def __str__(self):
        if self.color == 'white':
            return 'W' if not self.is_king else 'Wk'
        else:
            return 'B' if not self.is_king else 'Bk'

class Board:
    def __init__(self):
        self.grid = [[None for _ in range(8)] for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.grid[row][col] = Piece('white')

        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.grid[row][col] = Piece('black')

    def move_piece(self, start, end):
        piece = self.grid[start[0]][start[1]]
        self.grid[end[0]][end[1]] = piece
        self.grid[start[0]][start[1]] = None

    def print_board(self):
        for row in self.grid:
            print(' '.join(str(piece) if piece else '  ' for piece in row))
