        self.color = color

    def make_move(self, board):
        # Get user input for move
        start = input(f"Enter start position for {self.color} (e.g., 1a): ")
        end = input(f"Enter end position for {self.color} (e.g., 2b): ")

        # Convert input to positions and make the move
